INSERT INTO `v1_318f00d34af7d5e1a24ae7fc018b5da77c216034ddc147766b6d61bdc0105935` VALUES (91002, 7, 1, 10118, "フリーマーケット会場", 5118061, "フリーマーケットを訪れたジータが出会ったのは\n城をこっそり抜け出していたペコリーヌだった。", "ペコリーヌとの出会い", 20063115, 2, 40, "青空の下で謁見", 2834, 8, 0);
INSERT INTO `v1_318f00d34af7d5e1a24ae7fc018b5da77c216034ddc147766b6d61bdc0105935` VALUES (91002, 7, 1, 10118, "フリーマーケット会場", 5118062, "ジータたちがフリーマーケットを巡っていると\n露店を出していたマホに声をかけられる。", "マホとの出会い", 20063115, 2, 40, "未来の騎空団\nマスコット？", 2835, 8, 0);
INSERT INTO `v1_318f00d34af7d5e1a24ae7fc018b5da77c216034ddc147766b6d61bdc0105935` VALUES (91002, 7, 1, 10118, "ランドソル市街地", 5118063, "ジータが騎空団への依頼を確認していると、\n高笑いをしながらアキノが現れる。", "アキノとの出会い", 20063115, 2, 40, "お嬢さまからの\n緊急依頼", 2837, 8, 0);
INSERT INTO `v1_318f00d34af7d5e1a24ae7fc018b5da77c216034ddc147766b6d61bdc0105935` VALUES (91002, 18, 1, 10118, "フリーマーケット会場", 5118064, "ジータたちは、フリーマーケット会場で\n少し困った様子のジュンを見かける。", "ジュンとの出会い", 20063115, 2, 40, "黄金色の悩みごと", 4108402, 8, 0);
INSERT INTO `v1_318f00d34af7d5e1a24ae7fc018b5da77c216034ddc147766b6d61bdc0105935` VALUES (91002, 18, 1, 10118, "フリーマーケット会場", 5118065, "フリーマーケットの隅で開かれる格闘大会──\nそこにはカオリもいて……？", "カオリとの出会い", 20063115, 2, 40, "白熱！　格闘大会！", 4107402, 8, 0);
INSERT INTO `v1_318f00d34af7d5e1a24ae7fc018b5da77c216034ddc147766b6d61bdc0105935` VALUES (91002, 16, 1, 10118, "オーエド町", 5118066, "太鼓祭を控えるオーエド町──\nジータは、困った様子のニノンと出会う。", "ニノンとの出会い", 20063115, 2, 40, "祭り太鼓はオーエドの華", 9000227, 8, 1);
INSERT INTO `v1_318f00d34af7d5e1a24ae7fc018b5da77c216034ddc147766b6d61bdc0105935` VALUES (91002, 19, 1, 10118, "フリーマーケット会場", 5118067, "ビカラはイベントに出演中のスズナを見かける。\nしかし、スズナはどこか困っているようで……？", "スズナとの出会い", 20063115, 3, 40, "人気者は遅れて\nやってくる", 2101181, 8, 0);
INSERT INTO `v1_318f00d34af7d5e1a24ae7fc018b5da77c216034ddc147766b6d61bdc0105935` VALUES (91002, 18, 1, 10118, "ランドソル市街地", 5118068, "ビカラたちが街を散策していると、通りかかった\nナナカが興奮した様子で近づいてきて……？", "ナナカとの出会い", 20063115, 3, 40, "巫女・ミーツ・魔法少女", 4109402, 8, 0);
INSERT INTO `v1_318f00d34af7d5e1a24ae7fc018b5da77c216034ddc147766b6d61bdc0105935` VALUES (91002, 18, 1, 10118, "フリーマーケット会場", 5118069, "ネズ耳をなくしてしまい絶望するビカラ。同じ頃\nキャルとコッコロは落とし物を拾っており……", "キャル＆コッコロとの出会い", 20063115, 3, 40, "ネズ耳は二度なくなる", 4305402, 8, 0);
INSERT INTO `v1_318f00d34af7d5e1a24ae7fc018b5da77c216034ddc147766b6d61bdc0105935` VALUES (91002, 18, 1, 10118, "ランドソル市街地", 5118070, "街外れでひと休みをしていたビカラたちは、\nすっかりゴキゲンな様子のユカリと出会う。", "ユカリとの出会い", 20063115, 3, 40, "この出会いにカンパイ！", 4101402, 8, 0);
INSERT INTO `v1_318f00d34af7d5e1a24ae7fc018b5da77c216034ddc147766b6d61bdc0105935` VALUES (91002, 18, 1, 10118, "ランドソル市街地", 5118071, "ビカラは、人混みに怯えるアオイを心配し、\n陽気に声をかけるも……", "アオイとの出会い", 20063115, 3, 40, "陰陽アンサンブル", 4106402, 8, 0);
INSERT INTO `v1_318f00d34af7d5e1a24ae7fc018b5da77c216034ddc147766b6d61bdc0105935` VALUES (91002, 7, 1, 10118, "フリーマーケット会場", 5118072, "ビカラがフリーマーケット会場を歩いていると\n占いをしていたシノブに声をかけられる。", "シノブとの出会い", 20063115, 3, 40, "運試し十番勝負！", 2836, 8, 1);
INSERT INTO `v1_318f00d34af7d5e1a24ae7fc018b5da77c216034ddc147766b6d61bdc0105935` VALUES (0, 0, 0, 10118, 0, 5118600, 0, "オープニング", 20063115, 1, 0, "彼女たちの新たな日常", 0, 0, 0);
